// n8n Code Node - Split German Script into Sentences

// Get the input data
const inputData = $input.all();

// Function to split text into sentences
function splitIntoSentences(text) {
  // German sentence splitting - handles common abbreviations
  const sentences = text
    .replace(/([.!?])\s+/g, '$1|SPLIT|') // Mark sentence boundaries
    .replace(/([.!?])$/g, '$1|SPLIT|') // Handle end of text
    .split('|SPLIT|')
    .map(s => s.trim())
    .filter(s => s.length > 0); // Remove empty strings

  return sentences;
}

// Function to generate a unique ID
function generateId(index) {
  return `sent_${String(index + 1).padStart(4, '0')}`;
}

// Process the first item in the input
const item = inputData[0];
const germanScript = item.json['Scripts in German'];

if (!germanScript) {
  return [{
    json: {
      error: 'No "Scripts in German" field found'
    }
  }];
}

// Split the script into sentences
const sentences = splitIntoSentences(germanScript);

// Return array of items, each with a sentence object
return sentences.map((sentence, index) => ({
  json: {
    script_id: $input.first().json.id,
    id: generateId(index),
    sentence: sentence
  }
}));
